import os

def create_files():
    files = {
        "backend/app/workflows/engine.py": "from app.agents.core.state import SharedContext\nfrom app.agents.core.orchestrator import DAGOrchestrator\nfrom app.agents.impl.agents import (\n    InputValidationAgent, QRProcessingAgent, SecurityAnalysisAgent, \n    BrandVerificationAgent, RiskAssessmentAgent, ExplanationAgent, \n    RecommendationAgent, OfficialWebsiteVerificationAgent, ReportGenerationAgent\n)\nimport json\nimport asyncio\nimport logging\n\nlogger = logging.getLogger(__name__)\n\n# Configure Antigravity Workflow DAG\nantigravity_orchestrator = DAGOrchestrator({\n    \"Ingestion\": [InputValidationAgent(), QRProcessingAgent()],\n    \"Analysis\": [SecurityAnalysisAgent(), BrandVerificationAgent()],\n    \"Assessment\": [RiskAssessmentAgent(), OfficialWebsiteVerificationAgent()],\n    \"Synthesis\": [ExplanationAgent(), RecommendationAgent()],\n    \"Reporting\": [ReportGenerationAgent()]\n})\n\nasync def stream_workflow(target: str, scan_type: str):\n    context = SharedContext(original_target=target, scan_type=scan_type)\n    yield f\"data: {{ \\\"event\\\": \\\"step_start\\\", \\\"step\\\": \\\"Initializing Antigravity Engine...\\\" }}\\n\\n\"\n    await asyncio.sleep(0.5)\n    \n    for phase, agents in antigravity_orchestrator.agents_map.items():\n        yield f\"data: {{ \\\"event\\\": \\\"step_start\\\", \\\"step\\\": \\\"Executing {phase}...\\\" }}\\n\\n\"\n        \n        tasks = [agent.run(context.model_copy(deep=True)) for agent in agents]\n        results = await asyncio.gather(*tasks, return_exceptions=True)\n        \n        for agent, result in zip(agents, results):\n            if isinstance(result, Exception):\n                yield f\"data: {{ \\\"event\\\": \\\"partial_failure\\\", \\\"step\\\": \\\"{agent.name} failed\\\" }}\\n\\n\"\n            else:\n                for key, val in result.model_dump().items():\n                    if val is not None and (not isinstance(val, list) or len(val) > 0):\n                        setattr(context, key, val)\n                yield f\"data: {{ \\\"event\\\": \\\"step_complete\\\", \\\"step\\\": \\\"{agent.name} Success\\\" }}\\n\\n\"\n                \n    yield f\"data: {{ \\\"event\\\": \\\"workflow_complete\\\", \\\"state\\\": {context.model_dump_json()} }}\\n\\n\"\n",
        "backend/app/controllers/scan_controller.py": "from fastapi import APIRouter, Depends, UploadFile, File, Form\nfrom fastapi.responses import StreamingResponse\nfrom sqlalchemy.ext.asyncio import AsyncSession\nfrom app.database.session import get_db\nfrom app.schemas.scan import URLScanRequest, QRScanRequest\nfrom app.workflows.engine import stream_workflow\nfrom app.models.scan import Scan\nfrom app.models.details import ThreatResult, Recommendation, OfficialWebsite\nimport json\n\nrouter = APIRouter()\n\nasync def save_state_to_db(db: AsyncSession, state_dict: dict, user_id: int | None = None) -> int:\n    scan = Scan(\n        target=state_dict.get(\"original_target\"),\n        scan_type=state_dict.get(\"scan_type\"),\n        status=\"completed\",\n        risk_score=state_dict.get(\"risk_score\"),\n        risk_level=state_dict.get(\"risk_level\"),\n        confidence_score=state_dict.get(\"confidence\"),\n        user_id=user_id\n    )\n    db.add(scan)\n    await db.flush()\n    \n    for flag in state_dict.get(\"threat_intel_flags\", []):\n        db.add(ThreatResult(scan_id=scan.id, agent_name=\"ThreatIntelAgent\", status=\"Fail\", description=flag, passed=False))\n        \n    for rec in state_dict.get(\"recommendations\", []):\n        db.add(Recommendation(scan_id=scan.id, text=rec, priority=\"High\"))\n        \n    impersonated = state_dict.get(\"impersonated_brand\")\n    if impersonated:\n        db.add(OfficialWebsite(scan_id=scan.id, brand_name=impersonated, official_url=state_dict.get(\"official_url\", \"\")))\n        \n    await db.commit()\n    return scan.id\n\nasync def event_generator(db: AsyncSession, target: str, scan_type: str, user_id: int | None = None):\n    final_state = None\n    async for event in stream_workflow(target, scan_type):\n        # Check if it's the final payload\n        if \"workflow_complete\" in event:\n            data_str = event.split(\"data: \")[1].strip()\n            parsed = json.loads(data_str)\n            final_state = parsed.get(\"state\")\n        else:\n            yield event\n            \n    if final_state:\n        scan_id = await save_state_to_db(db, final_state, user_id)\n        yield f\"data: {{ \\\"event\\\": \\\"completed\\\", \\\"scan_id\\\": {scan_id} }}\\n\\n\"\n\n@router.post(\"/url\")\nasync def scan_url(scan_in: URLScanRequest, db: AsyncSession = Depends(get_db)):\n    return StreamingResponse(event_generator(db, str(scan_in.target_url), \"URL\"), media_type=\"text/event-stream\")\n",
        "frontend/src/pages/WebsiteScanner.tsx": "import React, { useState } from 'react';\nimport { useNavigate } from 'react-router-dom';\nimport { motion } from 'framer-motion';\nimport { Globe, ArrowRight, ShieldCheck, Search, CheckCircle2, Loader2, AlertTriangle } from 'lucide-react';\nimport api from '../utils/axios'; // Wait, SSE usually needs standard fetch or EventSource if it's a GET, but for POST we use fetch.\n\nconst WebsiteScanner = () => {\n  const [url, setUrl] = useState('');\n  const [isScanning, setIsScanning] = useState(false);\n  const [logs, setLogs] = useState<{message: string, type: 'start' | 'complete' | 'error'}[]>([]);\n  const [error, setError] = useState('');\n  const navigate = useNavigate();\n\n  const handleScan = async (e: React.FormEvent) => {\n    e.preventDefault();\n    if (!url) return;\n    setIsScanning(true);\n    setLogs([]);\n    setError('');\n\n    try {\n      const token = localStorage.getItem('access_token');\n      const response = await fetch('http://localhost:8000/api/scan/url', {\n        method: 'POST',\n        headers: {\n          'Content-Type': 'application/json',\n          'Authorization': `Bearer ${token}`\n        },\n        body: JSON.stringify({ target_url: url })\n      });\n\n      if (!response.ok) throw new Error(\"Stream failed to initialize\");\n      \n      const reader = response.body?.getReader();\n      const decoder = new TextDecoder();\n      \n      if (!reader) throw new Error(\"No stream reader\");\n\n      while (true) {\n        const { done, value } = await reader.read();\n        if (done) break;\n        \n        const chunk = decoder.decode(value, { stream: true });\n        const lines = chunk.split('\\n\\n');\n        \n        for (const line of lines) {\n          if (line.startsWith('data: ')) {\n            const data = JSON.parse(line.slice(6));\n            if (data.event === 'step_start') {\n              setLogs(prev => [...prev, { message: data.step, type: 'start' }]);\n            } else if (data.event === 'step_complete') {\n              setLogs(prev => [...prev, { message: data.step, type: 'complete' }]);\n            } else if (data.event === 'partial_failure') {\n              setLogs(prev => [...prev, { message: data.step, type: 'error' }]);\n            } else if (data.event === 'completed') {\n              setTimeout(() => navigate(`/app/results/${data.scan_id}`), 1000);\n            }\n          }\n        }\n      }\n    } catch (err: any) {\n      setError(err.message || 'Scanning interrupted');\n      setIsScanning(false);\n    }\n  };\n\n  return (\n    <div className=\"max-w-3xl mx-auto space-y-8\">\n      <div className=\"text-center space-y-4 mb-12\">\n        <div className=\"w-16 h-16 mx-auto bg-primary/20 rounded-full flex items-center justify-center\">\n          <Globe className=\"text-primary w-8 h-8\" />\n        </div>\n        <h1 className=\"text-3xl font-bold\">Website Scanner</h1>\n        <p className=\"text-gray-400\">Powered by Antigravity Multi-Agent Workflow.</p>\n      </div>\n\n      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className=\"glass-panel p-8\">\n        <form onSubmit={handleScan} className=\"space-y-6\">\n          <div>\n            <label className=\"block text-sm font-medium text-gray-300 mb-2\">Target URL</label>\n            <div className=\"relative\">\n              <Search className=\"absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 w-5 h-5\" />\n              <input \n                type=\"url\" required placeholder=\"https://example.com\"\n                className=\"w-full bg-surface border border-border rounded-xl pl-12 pr-4 py-4 text-white focus:outline-none focus:border-primary\"\n                value={url} onChange={(e) => setUrl(e.target.value)} disabled={isScanning}\n              />\n            </div>\n          </div>\n\n          {error && <div className=\"text-danger text-sm bg-danger/10 p-3 rounded\">{error}</div>}\n\n          {!isScanning ? (\n            <button type=\"submit\" className=\"w-full btn-primary flex items-center justify-center gap-2 py-4\">\n              Start Analysis <ArrowRight size={20} />\n            </button>\n          ) : (\n            <div className=\"space-y-4 bg-background p-4 rounded-xl border border-border h-64 overflow-y-auto font-mono text-sm\">\n              {logs.map((log, idx) => (\n                <motion.div key={idx} initial={{ opacity: 0, x: -10 }} animate={{ opacity: 1, x: 0 }} className=\"flex items-center gap-2\">\n                  {log.type === 'start' && <Loader2 className=\"animate-spin text-primary shrink-0\" size={16} />}\n                  {log.type === 'complete' && <CheckCircle2 className=\"text-success shrink-0\" size={16} />}\n                  {log.type === 'error' && <AlertTriangle className=\"text-danger shrink-0\" size={16} />}\n                  <span className={log.type === 'start' ? 'text-gray-400' : log.type === 'error' ? 'text-danger' : 'text-success'}>\n                    {log.message}\n                  </span>\n                </motion.div>\n              ))}\n            </div>\n          )}\n        </form>\n      </motion.div>\n    </div>\n  );\n};\n\nexport default WebsiteScanner;\n"
    }

    for path, content in files.items():
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "w", encoding="utf-8") as f:
            f.write(content)

if __name__ == "__main__":
    create_files()
    print("Stage 9 Scaffolded.")
